(window.webpackJsonp=window.webpackJsonp||[]).push([[311],{938:function(e,n){e.exports="\x3c!-- \ntitle: 调用摄像头\nsort: \n--\x3e \n\n```js\nlet opt = {\n  audio: false,\n  video: {\n    width: 720,\n    height: 480\n  }\n};\n\n// 获取摄像头对象\nnavigator.mediaDevices.getUserMedia(opt)\n  .then(mediaStream => {\n    let video = document.querySelector('video');\n    video.srcObject = mediaStream;\n    video.onloadedmetadata = e => {\n      video.play();\n    };\n  })\n  .catch(err => {\n    console.log(err.name + \": \" + err.message);\n  });\n\n// 拍照\nlet takePhoto = () => {\n  //创建canvas标签\n  let canvas = document.createElement('canvas');\n  canvas.width = 720;\n  canvas.height = 480;\n  //获取之前获取到的视频video标签\n  let video = document.querySelector('video');\n  //利用video画图\n  let context = canvas.getContext('2d');\n  context.drawImage(video, 0, 0, 720, 480);\n  //将canvas图像转换为base64字符串，设置格式以及压缩比例\n  let datauri = canvas.toDataURL('image/jpeg', 90 / 100);\n  //将base64字符串放入页面图片显示区域，显示拍照的图片\n  let photo = document.querySelector('img');\n  photo.src = datauri;\n  console.log(datauri);\n}\n```\n\n"}}]);